1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = {
14	  type: string;
15	  material?: string;
16	  enchantment?: number;
17	  cursed?: boolean;
18	};
19	type Step = { op: "quote"; items: Item[] };
20	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
21	
22	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
23	const BLOCK_SIZE = 3;
24	const BLOCK_BASE_PREMIUM = 60;
25	
26	const itemPremium = (item: Item): number => {
27	  const basePremium = BASE_PREMIUM_BY_TYPE[item.type];
28	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
29	  const cursedSurcharge = item.cursed === true ? basePremium * 0.5 : 0;
30	  return basePremium + cursedSurcharge + firstInsuranceSurcharge;
31	};
32	
33	const componentGroupBasePremium = (type: string, count: number): number => {
34	  if (count === BLOCK_SIZE) return BLOCK_BASE_PREMIUM;
35	  return count * BASE_PREMIUM_BY_TYPE[type];
36	};
37	
38	const quotePremium = (items: Item[]): number => {
39	  const componentItems = items.filter((item) => COMPONENT_TYPES.has(item.type));
40	  const mainItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
41	
42	  const mainTotal = mainItems.reduce((sum, item) => sum + itemPremium(item), 0);
43	
44	  const countsByType = componentItems.reduce<Record<string, number>>((acc, item) => {
45	    acc[item.type] = (acc[item.type] ?? 0) + 1;
46	    return acc;
47	  }, {});
48	
49	  const componentBaseTotal = Object.entries(countsByType).reduce(
50	    (sum, [type, count]) => sum + componentGroupBasePremium(type, count),
51	    0,
52	  );
53	  const componentTotal = componentBaseTotal + componentBaseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
54	
55	  return Math.ceil(mainTotal + componentTotal + PROCESSING_FEE);
56	};
57	
58	type QuoteResult = { premium: number };
59	
60	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
61	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
62	  return { results };
63	};
