const itemPremium = (item: Item): number => {
  const basePremium = BASE_PREMIUM_BY_TYPE[item.type];
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
  const cursedSurcharge = item.cursed === true ? basePremium * 0.5 : 0;
  const highEnchantmentSurcharge =
    (item.enchantment ?? 0) >= 5 ? basePremium * 0.3 : 0;
  return basePremium + cursedSurcharge + highEnchantmentSurcharge + firstInsuranceSurcharge;
};
